import React, { useEffect, useState } from 'react';
import Navbar from '../../components/Navbar';
import api from '../../api/axiosInstance';
import styles from './AdminPages.module.css';

const ManagePackagesPage = () => {

  const [packages, setPackages] = useState([]);
  const [destinations, setDestinations] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  const [formData, setFormData] = useState({
    name: '',
    destination: '',
    duration: '',
    price: '',
    availableSlots: '',
    description: '',

    // 🔥 NEW FIELDS
    transportation: '',
    sightseeing: '',
    accommodation: '',
    meals: '',
    itinerary: ''
  });

  // ================= LOAD DATA =================
  const load = async () => {
    try {
      setLoading(true);
      const res = await api.get('/packages');
      setPackages(res.data.data);
    } catch (err) {
      setError('Failed to load packages.');
    } finally {
      setLoading(false);
    }
  };

  const loadDestinations = async () => {
    try {
      const res = await api.get('/destinations');
      setDestinations(res.data.data);
    } catch (err) {
      console.error(err);
    }
  };

  useEffect(() => {
    load();
    loadDestinations();
  }, []);

  // ================= HANDLE CHANGE =================
  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  // ================= ADD PACKAGE =================
  const addPackage = async (e) => {
    e.preventDefault();

    try {

      const payload = {
        ...formData,

        // 🔥 CONVERT STRING → ARRAY
        transportation: formData.transportation.split(','),
        sightseeing: formData.sightseeing.split(','),
        accommodation: formData.accommodation.split(','),
        meals: formData.meals.split(','),
        itinerary: formData.itinerary.split(',')
      };

      await api.post('/packages', payload);

      alert("Package added successfully");

      setFormData({
        name: '',
        destination: '',
        duration: '',
        price: '',
        availableSlots: '',
        description: '',
        transportation: '',
        sightseeing: '',
        accommodation: '',
        meals: '',
        itinerary: ''
      });

      load();

    } catch (err) {
      console.error(err);
      alert("Failed to add package");
    }
  };

  return (
    <>
      <Navbar />

      <div className={styles.page}>
        <h1>✈️ Manage Packages</h1>

        <h2>Add New Package</h2>

        <form onSubmit={addPackage} className={styles.form}>

          <input
            type="text"
            name="name"
            placeholder="Package Name"
            value={formData.name}
            onChange={handleChange}
            required
          />

          <select
            name="destination"
            value={formData.destination}
            onChange={handleChange}
            required
          >
            <option value="">Select Destination</option>
            {destinations.map((d) => (
              <option key={d._id} value={d._id}>
                {d.name}
              </option>
            ))}
          </select>

          <input
            type="text"
            name="duration"
            placeholder="Duration (e.g. 4N/5D)"
            value={formData.duration}
            onChange={handleChange}
            required
          />

          <input
            type="number"
            name="price"
            placeholder="Price"
            value={formData.price}
            onChange={handleChange}
            required
          />

          <input
            type="number"
            name="availableSlots"
            placeholder="Available Slots"
            value={formData.availableSlots}
            onChange={handleChange}
            required
          />

          <textarea
            name="description"
            placeholder="Description"
            value={formData.description}
            onChange={handleChange}
          />

          {/* 🔥 NEW ARRAY INPUTS */}
          <textarea
            name="transportation"
            placeholder="Transportation (comma separated)"
            value={formData.transportation}
            onChange={handleChange}
          />

          <textarea
            name="sightseeing"
            placeholder="Sightseeing (comma separated)"
            value={formData.sightseeing}
            onChange={handleChange}
          />

          <textarea
            name="accommodation"
            placeholder="Accommodation (comma separated)"
            value={formData.accommodation}
            onChange={handleChange}
          />

          <textarea
            name="meals"
            placeholder="Meals (comma separated)"
            value={formData.meals}
            onChange={handleChange}
          />

          <textarea
            name="itinerary"
            placeholder="Itinerary (comma separated)"
            value={formData.itinerary}
            onChange={handleChange}
          />

          <button type="submit" className={styles.btn}>
            Add Package
          </button>

        </form>

        {/* ================= TABLE ================= */}
        {loading && <p>Loading…</p>}
        {error && <p style={{ color: "red" }}>{error}</p>}

        {!loading && !error && (
          <table className={styles.table}>
            <thead>
              <tr>
                <th>Name</th>
                <th>Destination</th>
                <th>Duration</th>
                <th>Price</th>
              </tr>
            </thead>

            <tbody>
              {packages.length === 0 ? (
                <tr>
                  <td colSpan={4}>No packages found.</td>
                </tr>
              ) : packages.map((p) => (
                <tr key={p._id}>
                  <td>{p.name}</td>
                  <td>{p.destination?.name || '—'}</td>
                  <td>{p.duration}</td>
                  <td>₹{p.price}</td>
                </tr>
              ))}
            </tbody>
          </table>
        )}

      </div>
    </>
  );
};

export default ManagePackagesPage;
